windowclass.script:
			function update()
				local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());

				realm.update(bReadOnly);
				class.update(bReadOnly);
				self["class_dropdown"].setVisible(not bReadOnly);
				text.update(bReadOnly);
	
				spells_iedit.setVisible(not bReadOnly);
				spells_iadd.setVisible(not bReadOnly);

				spells.setReadOnly(bReadOnly);
				for _,w in pairs(spells.getWindows()) do
					w.level.setReadOnly(bReadOnly);
					w.name.setReadOnly(bReadOnly);
					w.area.setReadOnly(bReadOnly);
					w.duration.setReadOnly(bReadOnly);
					w.range.setReadOnly(bReadOnly);
					w.type.setReadOnly(bReadOnly);
				end
			end
			local _bUpdatingDetail = false;
			function toggleListDetail()
				_bUpdatingDetail = true;
				local nValue = spells_detail.getValue();
				for _,w in pairs(spells.getWindows()) do
					w.activatedetail.setValue(nValue);
				end
				_bUpdatingDetail = false;

				self.onUpdateDetailToggle();
			end
			function onUpdateDetailToggle()
				if _bUpdatingDetail then
					return;
				end

				local nValue = 0;
				for _,w in pairs(spells.getWindows()) do
					if w.activatedetail.getValue() == 1 then
						nValue = 1;
					end
				end
				spells_detail.setValue(nValue);
			end

button_toggledetail.script:
function onButtonPress()
	window.toggleListDetail();
end
function onValueChanged()
end

windowclass.script:
function toggleDetail()
	if activatedetail.getValue() == 1 then
		text.setVisible(true);
	else
		text.setVisible(false);
	end
	windowlist.window.onUpdateDetailToggle();
end

string_listitem_center_underline.script:
					function action(draginfo)
						local nodeSpell = window.getDatabaseNode();
						local nodeSpellList = DB.getParent(DB.getParent(nodeSpell));
						local nodeChar = nil;
						local sPath = DB.getPath(nodeSpellList);
						if string.find(sPath, "characters") then
							nodeChar = DB.getParent(DB.getParent(nodeSpellList));
						end
						local rActor = nodeChar and ActorManager.resolveActor(nodeChar) or ActorManager.getActiveActor();

					-- actor can be nil; the roll still works with a non-player context
					if not rActor then
						local rActorTemp = ActorManager.getActiveActor();
						if rActorTemp then
							local nodeCharTemp = ActorManager.getCreatureNode(rActorTemp);
							if nodeCharTemp then
								for _, nodeSL in pairs(DB.getChildren(nodeCharTemp, "spells")) do
									if DB.getValue(nodeSL, "name", "") == sSpellListName then
										rActor = rActorTemp;
										break;
									end
								end
							end
						end
					end
					if not rActor then
						rActor = nil
						end

						local sSpellListName = DB.getValue(nodeSpellList, "name", "");
						local sSpellListNodeName = DB.getPath(nodeSpellList);
						local sRealm = DB.getValue(nodeSpellList, "realm", "");
						local nESFTotal = 0;
						local esf_value = DB.getValue(nodeSpellList, "esf", "0");
						if esf_value then
							nESFTotal = tonumber(esf_value) or 0;
						end
						if nESFTotal == 0 then
							local rActorTemp = ActorManager.getActiveActor();
							if rActorTemp then
								local nodeCharTemp = ActorManager.getCreatureNode(rActorTemp);
								if nodeCharTemp then
									for _, nodeSL in pairs(DB.getChildren(nodeCharTemp, "spells")) do
										if DB.getValue(nodeSL, "name", "") == sSpellListName then
											local esf_temp = DB.getValue(nodeSL, "esf", "0");
											if esf_temp then
												nESFTotal = tonumber(esf_temp) or 0;
											end
											break;
										end
									end
								end
							end
						end
						local sSpellName = DB.getValue(nodeSpell, "name", "");
						local sSpellNodeName = DB.getPath(nodeSpell);

						if nESFTotal < 0 then nESFTotal = 0; end

							local nSpellLevel = DB.getValue(nodeSpell, "level", 0);
							ActionBaseCasting.performRoll(draginfo, rActor, sSpellListName, sSpellListNodeName, sRealm, Rules_Spells.GetSpellFailure(nESFTotal), { sSpellName = sSpellName, sSpellNodeName = sSpellNodeName, nSpellLevel = nSpellLevel });
						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end

windowclass.script:
			function update()
				local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
				
				list.setReadOnly(bReadOnly);
				level.setReadOnly(bReadOnly);
				area.setReadOnly(bReadOnly);
				duration.setReadOnly(bReadOnly);
				range.setReadOnly(bReadOnly);
				type.setReadOnly(bReadOnly);

				text.setReadOnly(bReadOnly);
			end

stringc_column.script:
					local nodeSpellList = nil;

					function onInit()
						nodeSpellList = DB.getChild(window.getDatabaseNode(), "...");
						setValue(DB.getValue(nodeSpellList, "name", ""));
						if nodeSpellList then
							window.spelllistlink.setValue("spelllist", DB.getPath(nodeSpellList));
							window.spelllistlink.setVisible(true);
						end
					end
